/**
 * Purity analysis — classify functions as pure/branching/looping
 * to understand the expected deafness profile of a project.
 *
 * Usage: npx tsx src/dogfood-purity.ts [file-or-dir]
 */

import { resolve, relative, extname, join } from 'path';
import { readdirSync } from 'fs';
import { analyzePolyglotSource } from './polyglot-bridge';

const ROOT = resolve(import.meta.dirname, '..');

const IGNORED_DIRS = new Set([
  'node_modules', '.next', 'dist', 'build', '.git', 'coverage',
  '.wrangler', '__tests__', '.a0', '.gnosis', '.lake', '.tmp',
  'target', '.turbo',
]);

const SCANNABLE = new Set(['.ts', '.tsx', '.js', '.jsx']);

function walkSourceFiles(root: string): string[] {
  const files: string[] = [];
  const queue = [root];
  while (queue.length > 0) {
    const dir = queue.pop()!;
    let entries;
    try { entries = readdirSync(dir, { withFileTypes: true }); } catch { continue; }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        if (!IGNORED_DIRS.has(entry.name)) queue.push(join(dir, entry.name));
      } else if (SCANNABLE.has(extname(entry.name))) {
        files.push(join(dir, entry.name));
      }
    }
  }
  return files;
}

const target = process.argv[2] ? resolve(process.argv[2]) : resolve(ROOT, 'src');
const sampleSize = parseInt(process.argv[3] ?? '50', 10);

const allFiles = walkSourceFiles(target);
const sample = allFiles.slice(0, sampleSize);

console.log(`Purity analysis: ${relative(ROOT, target)}`);
console.log(`Scanning ${sample.length} of ${allFiles.length} files\n`);

let totalPure = 0, totalBranching = 0, totalLooping = 0, totalFuncs = 0;
const perFile: Array<{
  file: string; total: number; pure: number; branching: number; looping: number;
}> = [];

for (const filePath of sample) {
  try {
    const r = await analyzePolyglotSource(filePath);
    let pure = 0, branching = 0, looping = 0;
    for (const f of r.functions) {
      const edges = f.bettyResult.ast?.edges ?? [];
      const hasFork = edges.some(e => e.type === 'FORK');
      const hasCycle = f.bettyResult.diagnostics.some(
        d => d.code === 'VOID_METACOG_MISSING_CONVERGENCE'
      );
      if (hasCycle) looping++;
      else if (hasFork) branching++;
      else pure++;
    }
    const total = r.functions.length;
    totalPure += pure;
    totalBranching += branching;
    totalLooping += looping;
    totalFuncs += total;
    if (total > 0) {
      perFile.push({ file: relative(ROOT, filePath), total, pure, branching, looping });
    }
  } catch { /* skip */ }
}

// Per-file breakdown
console.log('File'.padEnd(50) + 'total  pure  branch  loop   purity');
console.log('-'.repeat(85));
for (const f of perFile.sort((a, b) => b.total - a.total)) {
  const purity = f.total > 0 ? (f.pure / f.total).toFixed(2) : '0.00';
  console.log(
    f.file.padEnd(50) +
    String(f.total).padStart(5) +
    String(f.pure).padStart(6) +
    String(f.branching).padStart(8) +
    String(f.looping).padStart(6) +
    '   ' + purity
  );
}

console.log('\n' + '='.repeat(85));
const purityRatio = totalFuncs > 0 ? totalPure / totalFuncs : 0;
console.log(`Total functions: ${totalFuncs}`);
console.log(`  Pure (no FORK, no loops):  ${totalPure} (${(totalPure/totalFuncs*100).toFixed(1)}%)`);
console.log(`  Branching (FORK but no loops): ${totalBranching} (${(totalBranching/totalFuncs*100).toFixed(1)}%)`);
console.log(`  Looping (has cycles):     ${totalLooping} (${(totalLooping/totalFuncs*100).toFixed(1)}%)`);
console.log(`\nPurity ratio: ${purityRatio.toFixed(3)}`);
console.log(`\nInterpretation:`);
if (purityRatio > 0.7) {
  console.log(`  HIGH PURITY (${(purityRatio*100).toFixed(0)}% pure) — this is a library of transformations.`);
  console.log(`  Expected sigma is high because pure functions are correctly deaf.`);
  console.log(`  Health thresholds should be shifted: sigma < ${(0.1 + purityRatio * 0.6).toFixed(2)} = healthy.`);
} else if (purityRatio > 0.4) {
  console.log(`  MIXED (${(purityRatio*100).toFixed(0)}% pure) — blend of computation and control flow.`);
  console.log(`  Standard health thresholds apply.`);
} else {
  console.log(`  LOW PURITY (${(purityRatio*100).toFixed(0)}% pure) — this is a stateful application.`);
  console.log(`  Most functions have control flow. Standard or stricter thresholds apply.`);
}
